/*
  Buffer Seguro — Preparação mínima
  Extrai APENAS o necessário para roteamento.
  Zero IA, zero lookup, zero risco.
*/
const raw = $input.first().json;
const body = raw.body || raw;
const event = body.event || '';

// Aceita qualquer evento de mensagem
const isMessageEvent = ['messages.upsert', 'messages.update', 'message'].includes(event);

// Extrair dados da primeira mensagem
const msgs = body.data?.messages || [];
const firstMsg = msgs[0];
const remoteJid = firstMsg?.key?.remoteJid || '';
const messageId = firstMsg?.key?.id || null;
const fromMe = firstMsg?.key?.fromMe || false;
const isGroup = remoteJid.endsWith('@g.us');

// Timestamp da mensagem
const timestamp = firstMsg?.messageTimestamp
  ? new Date(Number(firstMsg.messageTimestamp) * 1000).toISOString()
  : new Date().toISOString();

// Decisão: deve entrar na fila?
// SIM se: é evento de mensagem + é grupo + não é do bot + tem ID
const shouldQueue = isMessageEvent && isGroup && !fromMe && !!messageId;

return [{
  json: {
    // Roteamento
    should_queue: shouldQueue,
    is_message:   isMessageEvent,

    // Dados para wa_message_queue
    message_id:   messageId || `evt_${Date.now()}`,
    group_jid:    remoteJid,
    timestamp,

    // Payload completo (raw Evolution) para fila
    queue_record: shouldQueue ? {
      message_id: messageId,
      group_jid:  remoteJid,
      status:     'pending',
      payload:    body
    } : null,

    // Body original para forward ao v34
    original_body: body
  }
}];
